func GeneratePrivateKey(keyType string, keySize int, entropySource io.Reader) ([]byte, error) {
    switch keyType {
    case "RSA":
        return rsa.GenerateKey(entropySource, keySize)
    case "ECDSA":
        return ecdsa.GenerateKey(elliptic.P256(), entropySource)
    default:
        return nil, fmt.Errorf("unsupported key type: %s", keyType)
    }
}

