func CompileAndRun(inputReader io.Reader) (string, error) {
    // Read the input from the reader
    input, err := ioutil.ReadAll(inputReader)
    if err != nil {
        return "", err
    }

    // Create a temporary file to store the input
    tempFile, err := ioutil.TempFile("", "input")
    if err != nil {
        return "", err
    }
    defer os.Remove(tempFile.Name())

    // Write the input to the temporary file
    _, err = tempFile.Write(input)
    if err != nil {
        return "", err
    }

    // Close the temporary file
    err = tempFile.Close()
    if err != nil {
        return "", err
    }

    // Compile the input
    compiler := exec.Command("go", "build", tempFile.Name())
    compiler.Dir = filepath.Dir(tempFile.Name())
    compiler.Env = append(os.Environ(), "GOOS=linux", "GOARCH=amd64")
    compilerOutput, err := compiler.CombinedOutput()
    if err != nil {
        return "", fmt.Errorf("failed to compile input: %v\n%s", err, compilerOutput)
    }

    // Run the compiled program
    program := exec.Command(tempFile.Name())
    program.Dir = filepath.Dir(tempFile.Name())
    programOutput, err := program.CombinedOutput()
    if err != nil {
        return "", fmt.Errorf("failed to run compiled program: %v\n%s", err, programOutput)
    }

    // Return the output of the program
    return string(programOutput), nil
}

