package main

import (
	"errors"
	"fmt"
	"regexp"
)

type Basket struct {
	Name string
	Config map[string]interface{}
}

func NewBasket(name string, config map[string]interface{}) (*Basket, error) {
	if !isValidName(name) {
		return nil, errors.New("invalid name")
	}
	return &Basket{Name: name, Config: config}, nil
}

func isValidName(name string) bool {
	matched, _ := regexp.MatchString("^[a-zA-Z0-9_-]+$", name)
	return matched
}

func main() {
	basket, err := NewBasket("my-basket", map[string]interface{}{"color": "red"})
	if err != nil {
		fmt.Println(err)
		return
	}
	fmt.Println(basket.Name)
}

