```
import java.io.PrintWriter;
import java.io.StringWriter;
import java.util.logging.Logger;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class ErrorHandler {
    private static final Logger logger = Logger.getLogger(ErrorHandler.class.getName());

    public static void handleError(HttpServletRequest request, HttpServletResponse response, Exception e) {
        logger.log(Level.SEVERE, "Error processing request", e);

        response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        response.setContentType("text/html");

        StringWriter sw = new StringWriter();
        PrintWriter pw = new PrintWriter(sw);
        e.printStackTrace(pw);
        String stackTrace = sw.toString();

        String errorMessage = "An error occurred while processing your request. Please try again later.";
        if (e instanceof MyCustomException) {
            errorMessage = "An error occurred while processing your request. Please try again later.";
        }

        try {
            response.getWriter().println("<html>");
            response.getWriter().println("<head>");
            response.getWriter().println("<title>Error</title>");
            response.getWriter().println("</head>");
            response.getWriter().println("<body>");
            response.getWriter().println("<h1>" + errorMessage + "</h1>");
            response.getWriter().println("<pre>" + stackTrace + "</pre>");
            response.getWriter().println("</body>");
            response.getWriter().println("</html>");
        } catch (IOException ex) {
            logger.log(Level.SEVERE, "Error writing error page", ex);
        }
    }
}
```
This function takes an `HttpServletRequest` and `HttpServletResponse` object as input, as well as an `Exception` object that represents the error that occurred during request processing. It logs the error to the server log, sets the response status to `HttpServletResponse.SC_INTERNAL_SERVER_ERROR`, and sets the response content type to `text/html`. It then writes an HTML error page to the response, including the error message and the stack trace.

You can use this function in your web application by catching any exceptions that occur during request processing and calling the `handleError` function with the appropriate parameters. For example:
```
try {
    // Process the request
} catch (Exception e) {
    ErrorHandler.handleError(request, response, e);
}
```
This will catch any exceptions that occur during request processing and display an error page with the stack trace to the user.

