```
const { execSync } = require('child_process');

function executeShellCommand(command, options) {
  const { input, output, args } = options;

  // Set up input and output streams
  const inputStream = input ? fs.createReadStream(input) : null;
  const outputStream = output ? fs.createWriteStream(output) : null;

  // Execute the shell command
  const result = execSync(command, {
    input: inputStream,
    output: outputStream,
    args: args,
  });

  // Close input and output streams
  if (inputStream) {
    inputStream.close();
  }
  if (outputStream) {
    outputStream.close();
  }

  return result;
}
```
