Here is a sample Node.js function that retrieves block device information with options to ignore certain devices and majors:
```
const fs = require('fs');

function getBlockDeviceInfo(options) {
  const devices = fs.readdirSync('/sys/block');
  const ignoredDevices = options.ignoredDevices || [];
  const ignoredMajors = options.ignoredMajors || [];
  const result = [];

  devices.forEach(device => {
    if (ignoredDevices.includes(device)) {
      return;
    }

    const major = fs.readFileSync(`/sys/block/${device}/dev`, 'utf8');
    if (ignoredMajors.includes(major)) {
      return;
    }

    const info = {
      device,
      major,
      size: fs.readFileSync(`/sys/block/${device}/size`, 'utf8'),
      model: fs.readFileSync(`/sys/block/${device}/model`, 'utf8'),
      vendor: fs.readFileSync(`/sys/block/${device}/vendor`, 'utf8'),
    };

    result.push(info);
  });

  return result;
}
```
You can call this function with the following options:
```
const options = {
  ignoredDevices: ['sda', 'sdb'],
  ignoredMajors: [1, 2],
};

const blockDevices = getBlockDeviceInfo(options);
console.log(blockDevices);
```
This will output an array of objects, each representing a block device, with the following properties:

* `device`: The name of the block device (e.g. `sda`, `sdb`, etc.)
* `major`: The major number of the block device (e.g. `1`, `2`, etc.)
* `size`: The size of the block device in bytes
* `model`: The model name of the block device
* `vendor`: The vendor name of the block device

You can modify the `ignoredDevices` and `ignoredMajors` options to filter out specific devices or major numbers.

