const { spawn } = require('child_process');

function executeBinaryWithArgumentsAndAssertErrorOutput(binaryPath, args, expectedErrorOutput) {
  return new Promise((resolve, reject) => {
    const child = spawn(binaryPath, args);
    let errorOutput = '';
    child.stderr.on('data', (data) => {
      errorOutput += data.toString();
    });
    child.on('close', (code) => {
      if (code !== 0) {
        reject(new Error(`Binary exited with code ${code}`));
      } else if (!errorOutput.includes(expectedErrorOutput)) {
        reject(new Error(`Expected error output "${expectedErrorOutput}" but got "${errorOutput}"`));
      } else {
        resolve();
      }
    });
  });
}
```
You can then use this function like this:
```
executeBinaryWithArgumentsAndAssertErrorOutput('my-binary', ['arg1', 'arg2'], 'expected error output').then(() => {
  console.log('Binary executed successfully');
}).catch((error) => {
  console.error(error);
});
```
This will execute the binary with the specified arguments and assert that the error output contains the expected string. If the error output does not contain the expected string, the promise will be rejected with an error message. If the binary exits with a non-zero exit code, the promise will also be rejected with an error message.

