import configparser

class ConfigError(Exception):
    pass

def load_config(filename):
    config = configparser.ConfigParser()
    try:
        config.read(filename)
    except configparser.Error as e:
        raise ConfigError(f"Error reading configuration file {filename}: {e}")

    if not config.has_section("main"):
        raise ConfigError("Missing 'main' section in configuration file")

    if not config.has_option("main", "host"):
        raise ConfigError("Missing 'host' option in 'main' section of configuration file")

    if not config.has_option("main", "port"):
        raise ConfigError("Missing 'port' option in 'main' section of configuration file")

    return config["main"]["host"], config["main"]["port"]
