		n := r.URL.Query().Get("n")
		if n == "" {
			http.Error(w, "Missing 'n' parameter", http.StatusBadRequest)
			return
		}

		nInt, err := strconv.Atoi(n)
		if err != nil {
			http.Error(w, "Invalid 'n' parameter", http.StatusBadRequest)
			return
		}

		db, err := sql.Open("postgres", "user=postgres password=password dbname=mydb sslmode=disable")
		if err != nil {
			http.Error(w, "Error connecting to database", http.StatusInternalServerError)
			return
		}
		defer db.Close()

		rows, err := db.Query("SELECT date, count FROM mytable ORDER BY date DESC LIMIT $1", nInt)
		if err != nil {
			http.Error(w, "Error querying database", http.StatusInternalServerError)
			return
		}
		defer rows.Close()

		var tallies []Tally
		for rows.Next() {
			var t Tally
			err := rows.Scan(&t.Date, &t.Count)
			if err != nil {
				http.Error(w, "Error scanning rows", http.StatusInternalServerError)
				return
			}
			tallies = append(tallies, t)
		}

