@app.route('/savemoderation', methods=['POST'])
@login_required
def save_moderation():
    """Updates the approved state (true or false) of drawings."""

    timestamp = time()
    if request.method == 'POST':
        if request.form['approved'] == 'true':
            approved = True
        else:
            approved = False

        if request.form['drawing_id']:
            drawing_id = request.form['drawing_id']
            drawing = Drawing.query.get(drawing_id)
            drawing.approved = approved
            db.session.add(drawing)
            db.session.commit()
            flash('Drawing approved.')
        else:
            flash('Drawing not found.')

    return redirect(url_for('moderation'))

