const chai = require('chai');
const expect = chai.expect;

describe('Configuration Parser', () => {
  it('should parse a valid configuration file', () => {
    const config = parseConfig('config.json');
    expect(config).to.be.an('object');
    expect(config.port).to.equal(3000);
    expect(config.host).to.equal('localhost');
  });

  it('should throw an error if the configuration file is not found', () => {
    expect(() => parseConfig('config.json')).to.throw(Error);
  });

  it('should throw an error if the configuration file is invalid', () => {
    expect(() => parseConfig('config.json')).to.throw(SyntaxError);
  });
});
```
