import java.io.File;
import java.io.IOException;
import java.util.zip.ZipEntry;
import java.util.zip.ZipFile;

public class ArchiveExtractor {
    public static void extract(String archivePath, String destinationDir) throws IOException {
        File archiveFile = new File(archivePath);
        File destinationDirFile = new File(destinationDir);

        if (archiveFile.exists() && archiveFile.isFile()) {
            if (destinationDirFile.exists() && destinationDirFile.isDirectory()) {
                try (ZipFile zipFile = new ZipFile(archiveFile)) {
                    Enumeration<? extends ZipEntry> entries = zipFile.entries();
                    while (entries.hasMoreElements()) {
                        ZipEntry entry = entries.nextElement();
                        File entryFile = new File(destinationDir, entry.getName());
                        if (entry.isDirectory()) {
                            entryFile.mkdirs();
                        } else {
                            entryFile.getParentFile().mkdirs();
                            try (InputStream inputStream = zipFile.getInputStream(entry)) {
                                Files.copy(inputStream, entryFile.toPath(), StandardCopyOption.REPLACE_EXISTING);
