public class ZipExtractor {
    public static void extract(String zipFilePath, String destinationDir, boolean safeExtraction) throws IOException {
        ZipFile zipFile = new ZipFile(zipFilePath);
        Enumeration<? extends ZipEntry> entries = zipFile.entries();
        while (entries.hasMoreElements()) {
            ZipEntry entry = entries.nextElement();
            String entryName = entry.getName();
            File entryFile = new File(destinationDir, entryName);
            if (safeExtraction && entryFile.exists()) {
                // Skip the entry if it already exists in the destination directory
                continue;
