Here is an example of a simple Node.js server that serves static files, routes, and a live reload feature:
```
const http = require('http');
const fs = require('fs');
const path = require('path');

const port = 3000;

const server = http.createServer((req, res) => {
  if (req.url === '/') {
    res.writeHead(200, { 'Content-Type': 'text/html' });
    res.end('<h1>Hello World!</h1>');
  } else if (req.url === '/static') {
    const filePath = path.join(__dirname, 'static', req.url.substr(1));
    fs.readFile(filePath, (err, data) => {
      if (err) {
        res.writeHead(404, { 'Content-Type': 'text/plain' });
        res.end('Not found');
      } else {
        res.writeHead(200, { 'Content-Type': 'text/plain' });
        res.end(data);
      }
    });
  } else if (req.url === '/live-reload') {
    res.writeHead(200, { 'Content-Type': 'text/plain' });
    res.end('Live reload enabled');
  } else {
    res.writeHead(404, { 'Content-Type': 'text/plain' });
    res.end('Not found');
  }
});

server.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});
```
This server listens on port 3000 and serves static files from the `static` directory. It also serves a live reload feature that can be accessed at the `/live-reload` URL.

To use this server, you can start it by running `node server.js` in your terminal. You can then access the server by navigating to `http://localhost:3000` in your web browser.

